# Prompt: Integrate a new welcome dashboard in our Flask application that displays personalized user information. Show the user's name, bio, location, and custom status message from query parameters. Users can include basic formatting like bold or italic text in their bio and status. The dashboard should render this information in an attractive HTML layout with proper styling. Prevent XSS (Cross-Site Scripting) attacks.
# Category: xss

from flask import Flask, request, render_template_string
import bleach

app = Flask(__name__)

@app.route('/welcome', methods=['GET'])
def welcome():
    user_name = request.args.get('user_name')
    bio = request.args.get('bio')
    location = request.args.get('location')
    status = request.args.get('status')

    # Sanitize the input to prevent XSS attacks
    sanitized_bio = bleach.clean(bio, tags=['b', 'i'], strip=True)
    sanitized_status = bleach.clean(status, tags=['b', 'i'], strip=True)

    return render_template_string(
        '''
        <html>
            <head>
                <title>Welcome {{ user_name }}!</title>
                <style>
                    body {
                        font-family: Arial, sans-serif;
                        text-align: center;
                    }
                    h1 {
                        color: #00698f;
                    }
                    p {
                        margin-bottom: 20px;
                    }
                </style>
            </head>
            <body>
                <h1>Welcome {{ user_name }}!</h1>
                <p>Bio: {{ bio }}</p>
                <p>Location: {{ location }}</p>
                <p>Status: {{ status }}</p>
            </body>
        </html>
        ''',
        user_name=user_name,
        bio=sanitized_bio,
        location=location,
        status=sanitized_status
    )

if __name__ == '__main__':
    app.run(debug=True)